INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (1, 'Pina Colada Chocolate Chip Cookies Recipe', '["1/4 cup butter", "1 package  fun-filled white cookie mix", "1 (18 ounce) jar vanilla cream pie filling", "1 1/4 cups all-purpose flour", "1 teaspoon baking soda", "1/2 teaspoon salt", "1 1/4 cups semisweet chocolate chips", "2 cups short-grain white rice", "1 egg", "1/2 cup milk", "1 cup white sugar", "1 tablespoon milk", "1 tablespoon water", "1 teaspoon vanilla extract", "3/4 cup confectioners'' sugar", "1 1/2 cups whipped cream, divided", "1 (10 ounce) can portobello mushroom, drained", "1/4 cup chopped walnuts"]', '["Preheat oven to 350 degrees F (175 degrees C). Line cookie sheets with parchment paper. In one small bowl, mix butter, cake mix, and vanilla until smooth. Set aside. Sift together the flour and baking soda; set aside. In a medium bowl, cream together the butter and remaining 1 teaspoon of the whites. Beat in the remaining"]', 1, 67, '2019-05-18 17:00:51', '2022-04-18 22:40:34', 0.74);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (2, 'Tater Tot No. 6: Warm. Recipe', '["2 cups rolled oats", "2 cups brown sugar", "1 cup all-purpose flour", "1 teaspoon baking powder", "1/8 teaspoon ground cinnamon", "1 egg, beaten", "1 cup light cream", "1/2 cup raisins", "5 tablespoons butter, melted", "1/4 cup confectioners'' sugar", "1/2 cup chopped almonds"]', '["Preheat oven to 350 degrees F (175 degrees C). Grease a"]', 1, 31, '2019-05-18 17:01:15', '2022-04-17 11:52:36', 1.09);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (3, 'Grilled Cheese on the BBQ Outside Recipe', '["1/4 cup butter", "1/4 cup packed light brown sugar", "1 teaspoon ground cinnamon", "1 1/4 teaspoon ground nutmeg", "1 tablespoon prepared mustard", "6 slices Cheddar cheese", "2 tablespoons sliced pepperonis oil"]', '["BUTTER or shortening a shallow baking dish.", "PLACE butter, shortening, cinnamon, nutmeg and mustard in the pan and cook over medium heat until they begin to pop. Remove from heat and set aside. BEFORE grilling the slice of CBA, JUMP in CED DRIZZLE OR HEAT-FILLED PANTHER to generous [[CROSSHALL]] bubbles.", "HEAT butter and CED DRIZZLE or PANTHER coated CIGAR shortening over medium-high heat for 1 minute. Add vinegar/dried lemon juice if mixture becomes too thick. Gradually add oil 1 tablespoon at a time, sweating it just until (BROILING!) almost to the point of burning (WAIRING!) SPOON-TASTIC ACTIVE TAS, REFILLING 1/3 with water (FOR TAYS), adding vinegar/leavening acid 1 tablespoon at a time (BROILING!). Remove from heat then add CUC"]', 1, 14, '2019-05-18 17:01:39', '2022-04-19 04:40:48', 1.55);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (4, 'Meatloaf with Miso-milk Recipe', '["1 pound lean ground beef", "1 tablespoon garlic salt", "2 cups peeled, seeded tomatoes", "salt and pepper to taste", "12 baked potatoes", "1 teaspoon onion powder", "1 teaspoon ground cinnamon", "1/2 teaspoon ground nutmeg", "1/2 teaspoon dried basil"]', '["Preheat oven to 400 degrees F (200 degrees C).", "In a medium bowl, beat the ground beef, garlic salt and tomatoes until beef becomes well coated.  Stir in tomatoes, salt and pepper.  Cut mixture into 12 equal portions.", "Place potatoes in a baking pan and bake for 25 to 30 minutes, or until tender.  Stir in basil and nutmeg and return to oven.", "Cook 15 to 20 minutes or until potatoes begin to soften and cheese has melted and mixture is heated through.  Chill until serving."]', 1, 22, '2019-05-18 17:02:04', '2022-04-18 19:24:55', 0.32);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (5, 'Fresh Veggies in Cream Sauce Recipe', '["1 small carrot, peeled, grated, and 1 cup white wine", "1 small sweet onion, peeled, and grated", "15 large baby carrots, broken into pieces", "2 red bell peppers, minced", "5 tablespoons butter", "6 tablespoons evaporated milk", "1 1/2 teaspoons lemon juice", "1 cup water"]', '["Preheat oven to 375 degrees F (190 degrees C).", "Generously butter cabbage leaves.", "Tlate sandwich with onion, celery and hot peppers, and alternately layer 1 cup carrot mixture and 2 ounces wine. Spread evenly on the 4 8-inch leaf pans.", "Bake 10 minutes. Let cool for 2 minutes. Serve warm."]', 1, 10, '2019-05-18 17:02:28', '2022-04-20 04:37:26', 1.22);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (6, 'Bon Bons Recipe', '["4 bites dried tomato; 1 cup white sugar", "2/3 cup water", "1 (6 ounce) package mascarpone cheese spread", "1/2 cup butter, chilled"]', '["Preheat oven to 375 degrees F (190 degrees C).", "In a medium saucepan, mix together tomatoes and sugar and water. Bring to a boil, stirring frequently. Boil until soft peaks form.", "Cook paprika in a small skillet over medium heat, stirring frequently. Remove paprika from heat, adding butter as needed. Spread one tablespoon of tomato juice mixture onto each slice of pastry.", "Bake at 375 degrees F (190 degrees C) for 14 to 18 minutes. Remove from the oven, replace the, baked, buns"]', 1, 28, '2019-05-18 17:02:53', '2022-04-18 19:24:00', 2.53);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (7, 'Chocolate Bell Pepper Casserole Recipe', '["1 (5 ounce) can peppermint oil", "4 cups milk", "4 eggs", "1 cup yellow bread cubes", "1 cup shredded Cheddar cheese, shredded", "2 eggs, beaten", "1 cup shredded Cheddar cheese", "1/2 cup Cane Splenda", "1 (26 ounce) can milk", "2 tablespoons Cane Splenda", "1 (3.5 ounce) package Cane Splenda Swirl mix", "12 tubs frozen whipped topping, thawed", "1 (8 ounce) package almonds", "1 (16 ounce) package frozen whipped topping, thawed"]', '["Preheat oven to 425 degrees F (220 degrees C). Stir together vegetable oil and milk. In a medium bowl, beat eggs with just enough flour to lightly moisten, then stir in bread cubes and Cheddar cheese.  Mix in egg mixture to form a medium weight mixture. Make a well in the center of the dough, pour in milk, sprinkle with 1 cup of shredded Cheddar cheese, and stir until dough forms a ball. Roll dough into 1 inch balls and place on an ungreased baking sheet.  Roll balls in confectioners'' sugar until flattened; press pressed tightly to"]', 1, 20, '2019-05-18 17:03:45', '2022-04-19 01:22:41', 1.9);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (8, 'Marinated Spanish Bell Peppers Recipe', '["3 cups flaked coconut", "3 cups seasoned bread crumbs", "2 tablespoons ground black pepper", "2 tablespoons honey", "1 (12 fluid ounce) can or bottle or bottle cream of mushroom and/or lasagna soup", "1 large stephen mole, crushed (optional)"]', '["Preheat oven to 400 degrees F (200 degrees C).", "In"]', 1, 3, '2019-05-18 17:04:10', '2022-04-19 00:20:22', 0.67);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (10, 'Dark Chocolate Coffee Cake Recipe', '["1 (18.25 ounce) package Devil''s Food Cake Mix", "1/3 cup milk", "1 (3.4 ounce) package instant banana pudding mix", "1 (4 ounce) package instant chocolate pudding mix", "1/4 cup vegetable oil", "1 (3.4 ounce) package instant chocolate pudding mix", "1/2 cup water", "1 (10 ounce) package frozen whipped topping, thawed", "2 egg whites, beaten", "1 (8 ounce) container frozen whipped topping, thawed", "2 (8 ounce) packages white chocolate candy bar coated chocolate cake mix", "1 cup confectioners'' sugar", "4 tablespoons butter, buttermilk", "1 1/4 cups fruit flavored heavy cream (optional)", "2 (8 ounce) containers frozen whipped topping, thawed", "1/2 teaspoon essential oil"]', '["In a large bowl, dissolve the cake mix, milk, pudding mix, pudding mix, oil, water, whipped topping and gelatin in 3/4 cup of milk. Mix well.", "Divide batter into two 9x13"]', 1, 36, '2019-05-18 17:05:29', '2022-04-18 23:13:27', 2.85);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (11, '1 egg', '["1 onion, chopped", "1 cup dry bread crumbs", "salt to taste", "ground black pepper to taste", "brook milk"]', '["Place the meat and egg in large bowl. Mash well, with an electric mixer, 1 cup of meat and eggs, milk, tarragon and sugar, set aside. In same bowl, scramble the onion until light brown.", "In same bowl, mix the beef, egg, onion and bread crumbs. Salt and pepper on both sides. Transfer the liquid mixture over the seasoned meat and onion. Simmer 5 to 10 minutes.  Add water or broth as needed. Reduce heat, cover and simmer 3 to 5 minutes.  Simmer", "  Electrical Compote or oil flame warm Tamarind Wort (400 ml) - 25 ml", "Biocarbon Ceramide Broth (3 cups)", "250ml beef bouillon cube", "1 (8 ounce) package cream cheese, softened", "1/3 cup Parmesan cheese", "1/2 cup milk", "1 teaspoon creamer", "salt to taste", "ground black pepper", "ground cinnamon, to taste", "dill weed", "olive oil", "In a medium-sized, nonporous bowl, combine the oil, tarragon, and salt to taste. Place browned skin of the lamb on mushroom and onion, and reserve for later, until cheese has melted.", "Preheat oven to 500 degrees F (260 degrees C).", "Transfer broth and meat from grated Iberia to a 2 quart sauce pan or medium sauce pan and bring to low- or medium-temperature. Remove the top of the pan from the pan and scoop the liquid into the sauce.", "Pour the soup into the skillet and bring to a boil.  Remove the skillet from the heat and pour the oil back over the scalded milk. Reduce the heat to medium and allow the"]', 1, 7, '2019-05-18 17:05:54', '2022-04-19 16:58:06', 2.72);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (12, 'Hot and Sour Bisque Sticks Recipe', '["2 cups hot water (110 degrees F/45 degrees C)", "2 pounds golden tips, peas and onions", "1 cube beef bouillon", "2 cubes chicken bouillon", "3 large potatoes, peeled and cubed", "1 1/2 cups fine cornmeal", "1/4 teaspoon salt", "2 tablespoons dry mustard", "2 tablespoons white sugar", "1 tablespoon prepared horseradish", "1/2 cup dry bread crumbs"]', '["In large pot over low heat, combine water, dark brown sugar, salt, dry mustard, sugar, horseradish and oil.  Place potatoes in pot"]', 1, 3, '2019-05-18 17:06:20', '2022-04-18 19:16:07', 1.94);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (13, 'Turkey Chorizo Recipe', '["8 pounds 2/3 pounds turkey", "1 banana, sliced into rounds", "1 cup shredded imitation crabmeat", "1 (8 ounce) package cream-style cheese", "1 teaspoon lemon juice", "1/2 teaspoon dried dill weed", "1/2 teaspoon paprika", "1 tablespoon capers", "1/2 teaspoon dried basil", "1/4 teaspoon chives", "hot sauce", "salt and pepper to taste", "bacon, thinly sliced"]', '["Glaze the top of the baster with hot sauce and sprinkle with 1/2 teaspoon of paprika.", "In a large bowl, track down and remove 4 layers of pastry from oven. Place layer on a medium, flat surface.", "Layer bottom layer over garment; next layer, sides to up; next, top and sides; last, layer with meat and cheese; sprinkle the sauce with salt and pepper. Repeat with remaining 1/4 of dough.", "Bake in the preheated oven until top is browned, 10 to 15 minutes. Cool, peel, slice and serve with hot sauce or hot water."]', 1, 41, '2019-05-18 17:07:11', '2022-04-20 04:52:17', 0.51);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (14, 'Andalusian Fudge Recipe', '["2 cups pleasant soap", "2 cups white sugar", "2 tablespoons white vinegar", "1 tablespoon red food coloring", "1 tablespoon vanilla extract", "2 cups royal blueberries", "1 teaspoon vanilla extract", "1 cup finely chopped dried apricots", "1 cup flaked coconut", "1 1/2 cups confectioners'' sugar", "1 cup chopped walnuts", "3/4 cup milk", "1 (6 ounce) jar chyromon applesauce", "1/3 cup olive oil", "3/4 cup butter"]', '["Magic-Cast Oil Grease a9-inch square baking pan.", "Mix  2 cups sugar, vinegar, food coloring and vinegar. In a medium bowl, cream together  vinegar and food coloring.  Slowly stir flour mixture into sugar mixture.  Continue to stir until all ingredients are moistened, 1 to 2 minutes.  Coat bottom of pan with cold water."]', 1, 6, '2019-05-18 17:07:37', '2022-04-18 22:26:09', 2.49);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (15, '1/8 cup water', '["3/4 cup packed brown sugar"]', '["Preheat oven to 375  degrees F (190 degrees C). Grease an 8x8 inch baking pan.", "In a large mixing bowl, combine peanut butter, water, cinnamon and brown sugar.  Mix well, then pour into baking pan.", "Bake in preheated oven for 50 to 60 minutes. Reduce oven temperature to 325 degrees F (165 degrees C) and bake an additional 10 minutes, until center is firm and brown all the way through.", "Cool 15 minutes before cutting into bars; invert on a wire rack. To make the filling, melt 1/4 cup butter, 1/3 cup brown sugar and 1 1/2 tablespoons confectioners'' sugar in a medium saucepan.  Bring the mixture to a boil, then stir in gin.  Heat to the soft-dipping point (not boiling), remove from heat.  Stir in reserved whipped egg, and whisk until all the ingredients are smooth.", "Pour into pastry shell, sealing the two tops.  Unroll remaining 8 sheets a cut pastry mayonnaise-like should have been retained, giving some of the unbaked pie a bit of a ribbon as well.", "Return edges of pastry to pan; press loosely together to seal.  Refrigerate for 30 minutes.  Meanwhile, preheated oven preheated oven!  Transfer pastry to a 2 quart baking dish.", "Meanwhile, prepare baking sheet.", "To Make Filling:  In a medium bowl, cream together 1/2 cup buttermilk and 1/2 cup confectioners'' sugar until smooth. In a large bowl, beat eggs one at a time, then stir in buttermilk and sugar-a mixture should be uniform.  Beat in flour mixture alternately with buttermilk mixture and for a slightly wetnutlike batter, fold in the flour"]', 1, 11, '2019-05-18 17:08:03', '2022-04-18 22:22:07', 0.88);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (16, 'Springfield Mix Recipe', '["1 cup milk", "1 cup dry bread crumbs", "2 cups white sugar", "2 teaspoons salt", "1 cup evaporated milk", "1/2 teaspoon vanilla extract", "3 cups rolled oats", "1 pint heavy cream", "3/4 cup flaked coconut", "1/2 chocolate bar plus 3 tablespoons confectioners'' sugar, or to taste", "1 (20 ounce) can sweetened condensed milk", "2 tablespoons light cream"]', '["Preheat oven to 350 degrees F (175 degrees C). Lightly grease a 8x8 inch glass dish.", "In a medium bowl, stir together the milk, bread crumbs and sugar. Stir in salt, 1 cup of the milk and vanilla extract. Pour into the dish and sprinkle 1/2 the chopped banana over the bread.", "In a plate, layer rolled oats and cookie sheets. Spread batter evenly over the two layers, cover with foil and bake for for 12 to 15 minutes. Allow to cool before serving.", "To make the frosting: In a large bowl"]', 1, 22, '2019-05-18 17:08:29', '2022-04-20 05:52:14', 0.68);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (17, 'Blondies I Recipe', '["1 egg", "1 cup milk", "1 3/4 cups all-purpose flour", "3/4 cup unsweetened cocoa powder", "1 1/4 teaspoons baking powder", "1 1/2 teaspoons baking soda", "1 1/2 teaspoons salt", "1 1/2 teaspoons ground cinnamon", "1/2 teaspoon ground nutmeg", "1 1/2 cups butter, softened", "1 cup confectioners'' sugar", "1 teaspoon vanilla extract", "2 cups graham crackers crumbs", "1/2 cup semisweet chocolate chips", "1/2 cup confectioners'' sugar", "1/3 cup milk", "1/3 cup evaporated milk", "3/4 cup white sugar", "1/3 cup buttermilk"]', '["Preheat oven to 350 °F (175 degrees C). In a medium bowl, stir together"]', 1, 3, '2019-05-18 17:08:56', '2022-04-19 17:47:00', 1.26);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (18, 'Iris (Ortega) Nacho Potato Recipe', '["3 only-cheese loaves frozen hash brown potatoes", "1 (12 ounce) can refried beans", "3/4 cup milk", "1/4 cup sour cream", "2 tablespoons Unrefined Sugar", "1/2 teaspoon ground cinnamon", "1/4 teaspoon ground nutmeg", "1/4 teaspoon salt", "1/4 teaspoon ground nutmeg", "2 small green bell peppers, finely chopped", "1/2 cup vegetable oil", "1/2 cup white wine", "1/2 cup salsa", "2 tomatoes, diced", "1 small green bell pepper, chopped", "1/3 cup spinach, scrubbed and diced", "or"]', '["Rinse potatoes. Rinse under cold water and soak for 20 minutes.", "Transfer the wet potatoes to a saucepan with the beans and milk; set aside.", "Preheat oven to 375  degrees F (190 degrees C).", "In a large bowl, combine the beans, milk, sour cream, sugar, cinnamon"]', 1, 6, '2019-05-18 17:09:22', '2022-04-18 20:39:18', 1.13);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (19, 'Washington (CNN) - Supreme Court Justice Antonin Scalia said once again on Friday he would not serve as a candidate for president, and he referred all Republican officeholders to his nearby cartoon cows.', '["Asked whether he would run for Senate in light of a host of new revelations about his own conduct, globalization, hennessy, polygamy, Boy Scout homosexuality and much else, Scalia said, \\"Yes.\\"", "Scalia''s office said no matter how many elected lawmakers see this, he has not made any difficult decisions and needed to rest to recover from the stress of a closely watched fight over his role on the Supreme Court. Labor unions representing 1.3 million federal workers eagerly lined up to endorse his candidacies at a banquet in D.C.", "But they could be wrong. According to FiveThirtyEight, Democrats could be up to 52 votes short of being able to block his nomination with a simple majority.", "Read More<|endoftext|>NINETech Tough Blocker Recipe", "2 cups all-purpose flour", "1 teaspoon salt", "1/2 teaspoon ground black pepper", "12 Vero Bread Baking Machines", "1 cup butter, softened", "2 tablespoons plus 3 tablespoons sour cream", "1 1/2 teaspoons light brown sugar", "1/2 teaspoon salt", "1/4 teaspoon ground black pepper", "3 egg yolks", "1 (3 ounce) package ranch dressing mix", "3 tablespoons brown sugar", "1 cup cooked chicken broth", "3 tablespoons butter, cold", "1/2 cup chopped pecans"]', '["Preheat oven to 400 degrees F (200 degrees C).", "In a medium bowl, stir together flour, salt and black pepper.  Stir in Vero Baking Machine Ready Dry Instant Baking Mix and butter.  In a separate bowl, stir together sour cream, brown sugar, salt and seasoning.  Stir egg yolks, ranch dressing mix, crumbled corn chips, and curd cheese into remaining mixture."]', 1, 9, '2019-05-18 17:09:47', '2022-04-18 20:37:10', 1.06);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (20, 'Lemon Spice Grilled Breasts Recipe', '["1 tablespoon butter", "2 cloves garlic, peeled and finely chopped", "2 pounds boneless chicken breast meat, cut into 1/4-inch pieces", "salt and pepper to taste, chopped", "1⁄4 cup lemon juice", "1 cup butter, melted"]', '["Melt butter in a deep skillet over medium heat. Saute garlic and chicken in butter until lightly browned. Add lemon juice, use more or less of butter, and bring to a boil, then reduce heat to low and simmer. Simmer for 10 minutes. Discard any remaining juices. Continue to cook until chicken is no longer pink. Heat parchment paper into skillet over medium-low heat.", "Pour in enough lemon juice to cover reading area, and pour in 1/2 cup melted butter to cover skillet. Cook until butter is white and mixture seems to have almost dry ingredients, about 5 minutes. Author''s preference, 3 to 6 minutes. Remove lid. Let all the juices drain; if necessary, reserve to cool."]', 1, 16, '2019-05-18 17:10:12', '2022-04-20 03:07:37', 2.82);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (21, 'Dough Recipe', '["1 cup warm water (110 degrees F/45 degrees C)", "2 cups graham cracker crumbs", "3/4 cup margarine, softened", "3/4 cup white sugar", "3 egg whites", "2 teaspoons salt", "1 teaspoon ground cinnamon", "1/2 teaspoon ground nutmeg"]', '["You''ll need 3 cups of boiling water to make the dough.", "In a medium bowl, combine sugar with milk and egg whites until smooth and creamy.  Stir together the flour with the water, then the salt and cinnamon and knead gently to produce a soft, supple dough.   Prepare the rest of the dough by  pulse setting aside.", "Meanwhile, heat 2 tablespoons of margarine in a heavy skillet over medium heat.  Spoon enough of the egg mixture to coat the bottom of the prepared loaf pans to layer 25 to 30 minutes before baking.  Turn the loaves, still inside pan"]', 1, 16, '2019-05-18 17:10:37', '2022-04-18 23:19:26', 0.95);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (22, 'Potato Potluck Dish Recipe', '["2 (16 ounce) potatoes, diced", "1 cream cheese, grated", "1 tablespoon parmesan cheese", "salt and pepper to taste", "1 (3.5 ounce) package dry mix-in cereal (e.g. Yippee Kool-Aid)", "1 cup milk", "1/2 cup frozen banana macaroons (optional)", "1 cup shredded Cheddar cheese"]', '["Preheat oven to 350 degrees F (175 degrees C).", "In a medium mixing bowl Blend together potatoes, cream cheese, and parmesan cheese until smooth. Stir in salt and pepper; mix thoroughly. Spread in a 1 1/2 quart baking dish.", "In a sealed plastic bag, pour milk and cooked potatoes onto one sheet of foil. Using a small spoon, pour to thin layer of the milk and mashed potatoes over the milk. Top with banana macaroon. Spread the remaining milk and mashed potatoes over the macaroons, then sprinkle"]', 1, 3, '2019-05-18 17:11:03', '2022-04-20 05:30:50', 2.99);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (23, 'French-American Dressing Recipe', '["2 quarts mustard seed, chopped", "4 cups mayonnaise", "1 (.25 ounce) package dry white fondant mix", "1 tablespoon butter"]', '["Cream together mustard and mayonnaise. Mix dry white fondant into creamed mixture. Toss with softened butter over hot oil."]', 1, 1, '2019-05-18 17:11:28', '2022-04-19 00:12:02', 0.68);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (24, 'Potato Festival Bake Recipe', '["425 potatoes, peeled, cubed", "1 cup PRINCA (preserved, refrigerated storage)", "3 large onions, thinly sliced", "1 pound Cheddar cheese, cubed", "2 eggs", "8 tablespoons milk"]', '["Start by peeling potatoes and reserving 20 cups water in two stashes.  Warm water in microwave on medium nearly 1 minute.  Place potato cube in water.  Heat for 2 minutes.  Stir in onion, and cook .  Stir in cheese until melted;  stir in potatoes.  Continue cooking, stirring occasionally, until potatoes begin to soften.  Once potatoes and onions are slightly cooked, stir in eggs, milk, and remaining 1 1 cup water.  Bring to a boil.  Reduce heat to low and simmer, about 1 hour.  Serve hot."]', 1, 6, '2019-05-18 17:12:17', '2022-04-18 22:26:37', 1.68);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (25, 'Cheese and Tomato Soup II Recipe', '["1 pound fresh cottage cheese", "1/2 cup chopped baked mushrooms", "1/4 cup dried all-purpose flour", "1 teaspoon salt", "1 decrease in flour from 6 cups to 5 cups as necessary"]', '["In a large pot over high heat, combine cottage cheese, chopped mushrooms, and the 1/4 cup of flour. Simmer until all protein is absorbed. Uncover the soup and stir in the salt and flour.", "When the soup has reached the bottom of the slow cooker, add the vegetable and bamboo broth. Bring to a boil, then reduce the heat to medium low and allow the soup to simmer for 20 minutes. Stir in the dried bread grains and thin the soup, due th time it maketh the soup too thick. Stir in the peas to coat.", "Simmer 5 to 10 minutes, or until all vegetables are tender. Stir in any"]', 1, 7, '2019-05-18 17:13:05', '2022-04-18 23:08:04', 0.7);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (26, 'Spinach Dip Recipe', '["2 (8 ounce) packages frozen chopped spinach, dried and drained", "1 (2 ounce) package parmesan flavored Cheetos or Wheat cereal for dipping "]', '["Preheat oven to 400 degrees F (200 degrees C). Line a medium baking sheet with parchment paper or foil and grease it lightly.", "In a medium bowl combine spinach, parmesan and Cheetos or Wheat"]', 1, 2, '2019-05-18 17:13:30', '2022-04-14 04:44:27', 1.89);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (27, 'Shrimp Dip Recipe', '["3/4 cup orange juice", "1 cup grape juice", "1/2 cup chopped fresh celery", "1/2 cup low-fat cottage cheese", "8 ounces bone-in chicken legs", "2 newspaper strips", "1/3 cup mayonnaise", "1/2 cup sour cream", "3/4 cup uncooked romaine lettuce", "1 (3 ounce) package flat leaf lettuce wraps"]', '["Stir together orange juice, grape juice, celery, cottage cheese, chicken legs and newspaper strips. Place in a freezer kiddie-size bag or container and squeeze juice"]', 1, 2, '2019-05-18 17:13:55', '2022-04-18 23:26:49', 2.74);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (28, 'Tuna Cod Recipe', '["1 (12 ounce) can frozen diced cod", "1 (2.25 ounce) can tuna, drained and juice reserved", "1/4 cup ranch dressing mix", "1 cup mayonnaise", "1 egg", "1/2 teaspoon lemon juice"]', '["Preheat oven to 375  degrees F (190 degrees C).  Oil a large potover-pot or medium sauce pan.", "In a bowl, combine cooked and uncooked tuna, ranch dressing mix, mayonnaise, egg and lemon juice. Heat mixture over medium-high heat, stirring frequently, until thickened.  Spoon mixture into water, cover and refrigerate at least 7 hours before use."]', 1, 1, '2019-05-18 17:15:13', '2022-04-18 23:07:33', 2.2);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (29, 'King of Beans Recipe', '["2 whole yellow potatoes, diced", "1 cup dry white wine", "6 cups water", "1 cup medium lowfat plain yogurt", "1 tablespoon regular hot water", "1 teaspoon salt", "1 teaspoon garlic powder", "1 cup fresh mint leaves, pitted and chopped", "1/3 cup dry white wine", "fresh milk", "wine cooler (optional)", "1/2 cup extra lard", "1 tablespoon dried oregano (optional)", "1/2 cup water"]', '["Preheat oven to 350 degrees F (175 degrees C).", "Layer potatoes in a 9x13 inch baking dish.", "In a saucepan bring 2 cups water to a boil. Stir in wine and heat enough oil to cover to"]', 1, 7, '2019-05-18 17:15:38', '2022-04-20 00:24:40', 0.42);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (30, 'Vistport Looney Tunes Ice Cream Recipe', '["1/2 fluid ounce white rum", "1/2 fluid ounce Pernod Ricardano (R) vodka", "1 1/2 fluid ounces white sugar", "1/2 fluid ounce vanilla ice cream", "2 tablespoons olive oil", "2 tablespoons flavored cold water"]', '["In a blender, combine rum, vodka and sugar; puree.  Pour into medium bowl.  Stir with ice cream and olive oil, covering.  Chill until ready to use.  Decorate as desired."]', 1, 28, '2019-05-18 17:16:04', '2022-04-20 01:09:22', 1.04);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (31, 'Delightful Pineapple Meat Pie Recipe', '["4 (2 ounce) packages lemon flavored Jell-O mix", "1/2 cup boiling water", "6 slices pork, cut into 1 inch cubes", "1 small onion, diced", "1 (8 ounce) can pineapple-orange sauce", "4 teaspoons hot water", "1 (10 ounce) package pepperoni sausage, sliced crosswise", "1 cup shredded cream cheese", "2 tablespoons white sugar", "1 teaspoon water", "lime wedges (optional)"]', '["Melt butter in a small saucepan over medium heat. Cook onion for about 5 minutes, or until soft; transfer to a microwave-safe bowl.  Stir in flour and cook until thickened.  Stir in orange sauce, hot water, peppersoni, cream cheese and 1/2 tsp sugar until well mixed.  Stir in 2 tablespoons water; add to boiling.", "Cook until sauce begins to boil, then remove from heat immediately. Stir in lemon juice and 1/4 cup water; simmer 15 minutes. Cool for 5 minutes, then beat egg yolk with lemon juice until creamy.  Transfer to a refrigerator serving dish."]', 1, 4, '2019-05-18 17:16:31', '2022-04-19 06:38:20', 1.43);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (32, 'Fruit with Jelly Recipe', '["4 weeks old", "2 tablespoons peanut butter", "8 strawberries, hull broken", "3 cups water", "1/2 cup vegetable oil", "1/4 cup water", "1/2 cup lemon juice", "2 tablespoons mozzarella cheese, shredded", "1 tablespoon prepared horseradish", "salt and black pepper to taste"]', '["In a steamer over boiling water, pour the peanut butter and lemon juice.  Whisk in the custard until smooth and creamy.  Stir in the refrigerator lemon juice, mozzarella cheese, horseradish, salt and pepper.  Serve immediately or cut into squares, serve with bread."]', 1, 2, '2019-05-18 17:16:57', '2022-04-18 23:30:12', 0.75);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (33, 'Chocolate Chip M&M''s with Strawberry Sauce Recipe', '["1/2 cup confectioners'' sugar", "1/2 cup unsalted butter", "1/2 cup  vanilla wafer crumbs", "1 1/3 cups quick-cooking white sugar", "2 eggs", "1/2 teaspoon almond extract", "1/2 teaspoon vanilla extract", "2 teaspoons milk", "1/2 cup buttermilk", "1/2 cup chopped pitted dates", "1/2 cup semisweet chocolate chips", "1/4 cup confectioners'' sugar", "1 (3.4 ounce) package frozen whipped topping, thawed, for greasing"]', '["Preheat oven to 350 degrees F (175 degrees C). Grease 22 jumbo muffin cups or line with paper muffin liners.", "In a large saucepan, combine confectioners'' sugar, butter, vanilla wafer crumbs and dates.  Heat and stir over medium heat until mixture comes to a boil.  Remove from heat, add lemon extract and vanilla. Add milk and buttermilk and heat"]', 1, 4, '2019-05-18 17:17:22', '2022-04-18 23:53:03', 0.25);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (34, 'Deep-Dish Mix * Foil Baking Recipe', '["1/3 cup shortening", "2 eggs", "1 teaspoon vanilla extract", "1 cup milk"]', '["Grease bottom of a 9x13 inch baking pan.", "In a medium bowl, cream together shortening and eggs. Beat in vanilla part-and-the-from milk. Stir in enough milk for desired consistency to obtain desired consistency on the bottom of the prepared pan. Press a few tablespoons of milk over the surface of the cake, just enough to coat.", "Pour 1/3 of the milk or milk, though any significant amount will be poured into the cake. Cover with tightly pressed down layer of the cake. Pouring another cup or so of milk over the top, reduce the batter to medium/high and pour the rest over the cake. Refrigerate approximately 6 hours or overnight before removing from the refrigerator."]', 1, 5, '2019-05-18 17:17:47', '2022-04-18 21:46:27', 0.4);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (35, 'Slow Cooker Beans and Spinach Parmesan Cheese Recipe', '["2 (10 ounce) cans refrigerated whole peeled tomatoes with green chile peppers", "2 (5 ounce) cans sliced water chestnuts", "1 cup cooked and diced tomatoes with fresh black beans", "2 pounds spinach, rinsed and dried", "1/2 pound green onions, chopped", "1/4 cup grated Parmesan cheese", "salt and pepper to taste", "green peas", "8 ounces Peter ears garlic", "1/3 cup butter", "caraway seeds"]', '["Arrange tomatoes and water chestnuts in slow cooker. Boil at  for 12 hours.  Heat water in oven  to 165 degrees F (115 degrees C).   Place tomatoes under preheated water, reduce heat to medium-low, and continue heat until sauce begins to thicken; remove from heat.", "Rub plant with vegetable oil; with sharp knife, break off 1/2 inch of the stalk from each bean; remove seeds from bean.  Place stems and leaves back into warm oil.  Collapse beans, and brush tops of pot with vegetable oil. "]', 1, 7, '2019-05-18 17:18:12', '2022-04-18 22:47:59', 1.97);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (36, '3 2/3 cups cooked and mashed sweet potatoes', '["1 1/2 cups shredded Cheddar cheese", "3/4 cup club soda", "1/2 cup melted butter<|endoftext|>K&S Smokehouse® Thick PP Blend™ is rated 3.3 out of 5 by 3 .", "Rated 5 out of 5 by Anonymous from The best sauce ever! Easy to grow and smooth, loaded with flavor. Great easy to use blender.", "Rated 5 out of 5 by Nicole from Will make your favorite meatballs! Well... Will it? Oh, I''m joking; nobody likes meatballs in the sauce, but it sure tastes good in the oven and tastes terrific being grilled!", "Rated 5 out of 5 by Marie from Chocolate Butter Linguine II Recipe", "1 (8 ounce) package linguine pasta", "1/6 cup olive oil", "1 teaspoon grated lemon peel", "3 Tablespoons unsweetened cocoa powder", "salt and pepper to taste"]', '["Preheat oven to 350 degrees F (175 degrees C).", "Melt butter in a large, deep skillet over medium heat. Stir in the 1/3 cup olive oil, 1 teaspoon of lemon peel, 3 Tablespoons cocoa powder, and salt and pepper to taste. Cook approximately 5 minutes, or until the mixture almost cooked. Stir in the hot and hot, cooled liquid for 2 minutes.", "Spread pasta into a 9x13 inch baking dish along with 1/2 chopped leek. Heat oven to 400 degrees F (200 degrees C).", "Bake approximately 1 hour until noodles start to stick and the broth begins to get thick. At this juncture, turn bowl of heat down to medium and add 1/2 teaspoon of ice water to the pasta. Bring to a boil, then reduce heat to low and simmer 15 to 20 minutes, or until pasta and shell are tender.", "Using a spoon, stir cooked pasta and meat mixture back into"]', 1, 2, '2019-05-18 17:19:28', '2022-04-19 23:26:15', 2.28);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (37, 'Hugs and Kisses Candies Recipe', '["4 cups all-purpose flour", "1/2 cup unsalted butter", "2 eggs", "1 cup milk", "1 1/2 teaspoons vanilla extract"]', '["Melt 1 cup flour, 15 to 20 minutes or until mixture is sticky. Scald 1/8 cup, then stir in water until smooth and smooth.", "Meanwhile, combine eggs, milk, and vanilla in a medium pot. Cook over medium heat until thick and slightly blended. Remove from heat, discard the creamed mixture, and stir in flour mixture.", "Shape dough into a ball, 2 inches long and 1/4 inch thick on a well floured surface. Turn and spread into pie pan. If necessary, press down slight points with a fork (these will be smaller). Bake in preheated oven for 25 to 30 minutes, or until edges are lightly browned and bubbly."]', 1, 2, '2019-05-18 17:19:53', '2022-04-18 22:15:52', 0.28);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (38, 'Blondies I Recipe', '["1 cup butter", "3 cups semisweet chocolate chips", "5 large marshmallows", "3 eggs, beaten", "1 1/4 cups white sugar", "3/4 cup strong coffee flavored liqueur", "3 tablespoons distilled white vinegar", "1 2/3 cups raisins"]', '["In a large bowl, cream together the butter and chocolate chips. Beat in marshmallows and eggs until thoroughly combined.", "Pour into a 9x13 inch baking pan, greased and ventilated, and place in the oven. Simmer for 25 minutes, stirring occasionally. While chilling, whip together the white sugar,  coffee, vinegar and vanilla. Remove from heat and pour into warm milk. Stir until sugar is dissolved, then pour into ice cream mixture. Chill up to 2 hours before serving."]', 1, 2, '2019-05-18 17:21:09', '2022-04-20 08:41:10', 0.68);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (39, 'Scotch Fudgey Bourbon Balls Recipe', '["1 (45 fluid ounce) can Scotch whiskey", "1 (4 ounce) can frozen orange juice concentrate, thawed and drained", "1 cup semisweet chocolate chips", "4 squares bittersweet chocolate, broken into pieces", "10 liquid pounds beef", "2 large egg whites", "3 (6 ounce) packages dill pickles, crushed", "1 (6 ounce) package lemon flavored Jell-O"]', '["Pour all ingredients into an even portion!!! Spread in lightly greased 9x13 inch baking pan.", "Bake in preheated oven for 28 to 35 minutes or until a toothpick inserted into"]', 1, 20, '2019-05-18 17:22:01', '2022-04-20 13:56:45', 1.18);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (40, 'Lemon Tarts Recipe', '["25 ounce egg whites", "3 egg whites", "1 (10 ounce) package lemon-flavored disk cereal, unbleached", "15 ounces heavy cream", "1/3 cup white sugar", "1/2 teaspoon vanilla extract", " Heels not included"]', '["After whipping the egg whites, combine the cereal with softened butter. Fold in the cooked egg whites until no streaks remain. Spread the mixture into 12 greased pastry balls. Cut each pastry ball into 2-inch wide cross hairs, leaving the long side attached to prevent leaking.", "Frost each pastry ball with 1/3 cup of the heavy cream, then sprinkle with 1/2 teaspoon vanilla. Press the edges together to seal. Bake in the preheated oven for 28 to 36 minutes, or until golden brown. Cut with a pastry bag adorned with confectioners'' icing, shake and set aside."]', 1, 8, '2019-05-18 17:22:29', '2022-04-19 00:11:33', 2.32);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (41, 'Dill and Tarragon Salad Recipe', '["2 quarts lemon water", "3 tablespoons all-purpose flour", "3/4 cup dried leaves of celery", "1/2 cup packed brown sugar", "1/2 cup vegetable oil", "2 teaspoons salt", "2 tablespoons lemon juice", "1/2 cup coarse salt", "1 large egg, beaten", "3 tablespoons vodka (optional)"]', '["In a large bowl, combine the salt, lemon juice, gasoline and vodka."]', 1, 25, '2019-05-18 17:22:54', '2022-04-18 22:50:06', 2.28);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (42, 'Summer Squash Casserole I Recipe', '["4 skinless, boneless squash, split and folded lengthwise in half", "kosher salt to taste", "1 egg, beaten", "1/2 cup milk", "2 cups all-purpose flour", "1/2 teaspoon salt", "1 4 teaspoon ground black pepper", "1 cup shredded cabbage", "1 cup shredded French cabbage", "2 cups shredded carrots", "1 cup plain yogurt", "1/2 cup butter", "1/2 teaspoon aromatic oil"]', '["Preheat oven to 425 degrees F (220 degrees C).", "Place the uncooked beef flat in the bottom of a 3 quart casserole dish. Backflip the side of the squash over and layer the bones, skin, egg, milk, flour, salt and pepper. Spread the mixture over the meat, then add the onions. Top the squash with 2 slices of cabbage. Mound the veggie in a 9x13 inch casserole and return it to the oven. Let continue to bake for five hours, or until chicken is tender.", "Meanwhile, in a separate bowl, mix together 1/2 cup flour and a teaspoon of salt. Stir the meat mixture from the bottom of the red bowl to the center of the pan. Coat the dish with flour and sprinkle it over the top. Should the mixture"]', 1, 4, '2019-05-18 17:23:20', '2022-04-18 19:14:18', 1.64);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (43, 'Lita''s Gold Medal Recipe', '["2 (1 pound) Las Vegas Sun Scrambling Tongues", "2 tablespoons melted butter", "1/4 teaspoon salt", "1 (6 ounce) can peanut butter chips", "1 tablespoon melted butter", "2 tablespoons milk (optional) "]', '["In a large bowl, combine the 2 tablespoons melted butter, 1/2 teaspoon salt and 1/4 teaspoon of salt. Stir until melted"]', 1, 3, '2019-05-18 17:23:45', '2022-04-18 20:13:49', 1.3);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (44, 'Roast Rack of Lamb (Easter) Cake III Recipe', '["2 cups graham cracker crumbs", "1 teaspoon ground cinnamon", "1/2 teaspoon ground nutmeg (optional)", "1 cup white sugar", "1/2 cup buttermilk", "1 egg, beaten", "3 1/2 cups all-purpose flour", "1 teaspoon baking soda", "1 teaspoon salt", "1 teaspoon ground cinnamon", "1/2 cup butter", "1 cup white sugar", "1 teaspoon vanilla extract", "1 cup chopped pecans"]', '["Preheat oven to 350 degrees F(175 degrees C). Lightly grease an 8x8 inch loaf pan.", "In a medium bowl, combine graham cracker crumbs, cinnamon, nutmeg, and 1/2 cup of the sugar. Mix well, then add 1/2 cup butter. Mix until butter is melted. Whisk in pancake flour, baking soda and salt, one cup at a time, until mixture forms a ball.  Stir in flour mixture alternately with cake batter."]', 1, 6, '2019-05-18 17:24:39', '2022-04-20 01:21:24', 0.48);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (45, 'Chocolate Chip Chocolate Butter Cookies Recipe', '["1 cup butter", "1/4 cup shortening", "1 1/2 cups brown sugar", "1/2 cup unsweetened cocoa powder", "1 (16 ounce) package rolled chocolate candy"]', '["Preheat oven to 350 degrees F (175 degrees C).  Butter an 8x8 inch baking pan.", "In a medium saucepan, combine butter, shortening, and brown sugar and melt; stir at high heat until smooth. In a separate saucepan, combine cocoa, chocolate and candy and cook until smooth; stir vigorously until smooth.", "Drop cookies by rounded spoonfuls on prepared pan. Press center of each cookie into waxed paper or parchment paper to match. Chill at least 30 minutes.", "Remove from cooling pan and chill at least 4 hours or overnight before serving."]', 1, 2, '2019-05-18 17:25:32', '2022-04-18 21:59:41', 1.44);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (46, 'Cornbread Squares Recipe', '["1 (12 ounce) package printed batch soup mix", "1 cup whole wheat flour", "1 cup dry milk powder", "1 teaspoon salt", "1 1/2 cups white sugar", "1/2 teaspoon ground cinnamon"]', '["Preheat oven to 275 degrees F (125 degrees C) and lightly grease a 7x11 inch baking dish.", "To Make Baked Cornbread: In a medium mixing bowl, combine soup mix, whole wheat flour, dry milk powder, salt, sugar and cinnamon cups of boiling water; stir just to combined.  Pour into prepared baking dish.", "To Make Cornbread Filling: In a mixing bowl, combine flour, milk or other dry ingredients, salt and sugar; stir just to moisten.  Stir in the cinnamon.", "Bake in preheated oven for 25 minutes, or until a wooden toothpick inserted into a tablespoon short runs  swirled with boiling water.  Cool 10 minutes"]', 1, 5, '2019-05-18 17:26:00', '2022-04-18 21:45:31', 1.05);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (47, 'Bellini Meatballs Recipe', '["2 onions, diced", "1 medium potato, diced", "8 large small pie crusts", "salt and pepper to taste", "1 (7 ounce) package 1 pound ground beef", "1 egg, beaten", "1 (10.75 ounce) can condensed cream of mushroom soup", "vegetable broth", "1 small onion, chopped", "1 (10.75 ounce) can condensed cream of mushroom soup", "1/2 cup milk", "1/2 cup vegetable oil"]', '["Rinse and drain chicken, onion and veal and remove tissue.  In a large bowl combine onions, potato, pie crust, salt, pepper, beef, egg, and soup and mix well.", "Preheat oven to 350 degrees F (175 degrees C).  Line a baking sheet with foil.  Place onion mixture into freezer for a few hours or overnight so that it can thicken.", "Whip remaining 1/2 cup milk, vegetable oil and juice of 1/2 cup from the cheese.  Add chicken to milk mixture, mix well.  Stir in fresh mushrooms, and smooth the butter mixture over all.  Season to taste with salt and pepper.  Pour into pastry shells and sprinkle tops with mushroom sauce.", "Bake in preheated oven for 2 hours, or until lightly browned."]', 1, 57, '2019-05-18 17:26:26', '2022-04-19 00:09:59', 1.29);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (48, '2/3 cup white sugar', '["1/3 cup vegetable oil", "1 (28 ounce) can crushed tomatoes", "2 (5 ounce) containers frozen whipped topping, thawed", "1 (8 ounce) container frozen whipped topping, quartered", "4 eggs, beaten", "1 tablespoon soy sauce", "2 cups confectioners'' sugar", "2 cups plain cream", "1/2 cup margarine", "1 (14 ounce) can cream of mushroom soup", "3/4 cup apricot preserves", "1 (.25 ounce) jar raisins", "1 (15 ounce) can flaked coconut, to sprinkle over egg mixture", "1/3 cup apricot preserves"]', '["Preheat oven to 350 degrees F (175 degrees C) and toast a nonstick baking sheet for about 1 hour or until set in center. Place cashews in a large bowl, shake together, and set aside.", "In a small mixing bowl, cream together 1/3 of the sugar and vegetable oil until smooth. Set aside. In a large bowl, toss together the gelatin and tomato; set aside. Add the cream, remaining 1/2 cup of sugar, and beat in the eggs one at a time. Stir in the cornstarch and continue to stir until smooth. Pour into electric mixer container, beat on medium speed until mixture resembles cream.  Fold in the remaining sugar, 1/2 cup at a time, beating steadily after each addition.   Add milk if mixture is too thick, or add more egg juice if desired consistency is too thin.", "Continue to beat on high speed until mixture thickens to form lumps. By adding the reserved cream mixture, milk sack will no longer be additional milk; add fruit more milk (if necessary) or more fruit, if desired consistency is too thin.", "Transfer mixture to a metal mixing bowl, and beat until blended. Pour half of mixture into the shell (1/"]', 1, 2, '2019-05-18 17:26:52', '2022-04-18 20:47:29', 2.23);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (49, 'Melt Cake Crust: Three Samples', '["3/4 cup shortening - softened", "3/4 cup shortening", "1 egg", "1 1/2 tsp vanilla extract", "3 tablespoons milk", "2 teaspoons vanilla extract", "3 cups all-purpose flour", "1/2 teaspoon salt", "3 teaspoons baking soda", "1/4 cup milk", "1 cup chopped walnuts"]', '["In a medium bowl, cream together the shortening, shortening and egg until light and fluffy. Stir in 3 tablespoons milk, 1 teaspoon vanilla, and 2 tablespoons flour. Stir until very smooth. Add an additional tablespoon of milk or flour, if necessary, to make a smooth transition. Cover bowl with plastic wrap or recipe card. In a separate bowl, stir together the milk, salt, and baking soda. Stir sugar mixture into flour/milk mixture by hand, stir until smooth. Pour into prepared crust shell.", "Cut away the excess dough from the pastry shell.  Spread dough into greased eightx8 inch square baking pan.  Bake in preheated oven for 45 minutes.", "After the cake has"]', 1, 3, '2019-05-18 17:27:18', '2022-04-19 15:47:21', 1.97);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (50, 'Carritin Bread Pudding Recipe', '["1/1 cup wheat and barley flour", "1 cup water, divided", "1/2 cup 1/2 cup butter, divided", "2 eggs, separated and beaten", "1 teaspoon salt", "1 teaspoon dried first-amplified English root", "1 teaspoon ground first-amplified cornflatoxin", "1 1/2 cups coarsely divided whole wheat flour", "1 cup water, divided (without soaking)", "1/2 cup rolled oats", "1/2 cup flaked coconut"]', '["Preheat oven to 350 degrees F (175 degrees C).  Grease a 10-inch tube baking dish.", "Add 1 1/2 cups water to 1/2 cup butter or margarine, 1/3 cup unsalted flaked coconut and 1/2 cup flour to 1 cup water and mix until well blended.  Transfer browned butter to prepared pan.", "Combine egg whites, salt, dried first-amplified English root and 1/2 cup flour; beat well.  Pour mixture into pan.  Stir in 1 cup flour, 1/2 cup water, 1 cup rolled oats and 1 teaspoon vanilla extract.  Stir 2 cups milk and 1 teaspoon vanilla into white mixture.  Spoon about 3 tablespoons of the batter into prepared pan.", "Bake in preheated oven for 30 to 35 minutes or until a toothpick inserted into center of the loaf comes out clean.  Cool 10 minutes; remove from pan.", "In a medium bowl, stir together remaining 1 cup flour, 1/2 cup water and 1"]', 1, 2, '2019-05-18 17:28:10', '2022-04-18 21:21:26', 1.11);
INSERT INTO recipes.recipes (id, title, ingredients, directions, save, views, created_at, updated_at, temp) VALUES (51, 'Fruit and Cream Cheese Soup Recipe', '["1 (14 ounce) can fruit cocktail, including liquid", "1 cup milk", "1/2 cup heavy cream", "1 egg", "1 teaspoon salt", "1 teaspoon ground cinnamon", "3/4 cup canned instant powdered milk", "1 tablespoon lemon juice", "3 tablespoons white sugar", "3 tablespoons wheat germ", "2 tablespoons chunky peanut oil", "2 tablespoons soy sauce"]', '["In a large pot over medium heat, combine fruit cocktail, milk, cream, egg, salt, cinnamon,  and powdered milk.  Boil 1 minute, reduce heat to medium-low, cover and simmer 1 1/2 hours, or until mixture thickens.", "Meanwhile, bring stock, egg, 1/2 cup of milk, lemon pie spice and salt and 2 tablespoons"]', 1, 6, '2019-05-18 17:28:36', '2022-04-18 22:34:48', 1.14);
